import React, { memo, useState } from 'react'
import type { FC, ReactNode } from 'react'
import { Table, Sheet, Typography, IconButton, Tooltip, Box, Button, Input } from '@mui/joy'
import KeyboardArrowDownIcon from '@mui/icons-material/KeyboardArrowDown'
import KeyboardArrowUpIcon from '@mui/icons-material/KeyboardArrowUp'
import ContentCopyIcon from '@mui/icons-material/ContentCopy'
import CheckCircleRoundedIcon from '@mui/icons-material/CheckCircleRounded'
import ErrorOutlineRoundedIcon from '@mui/icons-material/ErrorOutlineRounded'
import DownloadIcon from '@mui/icons-material/Download'

interface Iprops {
  children?: ReactNode
  data: any[]
}

const ResultTable: FC<Iprops> = ({ data }) => {
  const results = typeof data === 'string' ? JSON.parse(data) : data
  const [openIndex, setOpenIndex] = useState<number | null>(null)

  console.log('Results:', results)

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text)
  }

  const downloadTSV = () => {
    const header = ['Name', 'ID', 'Search Sequence', 'Candidate ASO Sequence', 'Status', 'Description'].join('\t')
    const tsvContent = results
      .map((r: any) => {
        const desc = r.information?.warning || r.information?.error || ''
        return [r.id, r.number, r.search || '', r.aso || '', r.status, desc.replace(/\n/g, ' ')].join('\t')
      })
      .join('\n')

    // 获取当前时间字符串，格式为 MMDDYYYY_HHmm
    const now = new Date()
    const pad = (n: number) => n.toString().padStart(2, '0')
    const timestamp = `${pad(now.getMonth() + 1)}${pad(now.getDate())}${now.getFullYear()}_${pad(now.getHours())}${pad(
      now.getMinutes()
    )}`

    const blob = new Blob([`${header}\n${tsvContent}`], {
      type: 'text/tab-separated-values'
    })

    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    const filename = `aso_design_results_${timestamp}.tsv`
    a.href = url
    a.download = filename
    a.click()
    URL.revokeObjectURL(url)

    // ===== Store in localStorage =====
    try {
      const historyKey = 'aso_design_results_history'
      const history: any[] = JSON.parse(localStorage.getItem(historyKey) || '[]')

      const serialized = JSON.stringify(results)
      const exists = history.some((item) => item.serialized === serialized)

      if (!exists) {
        history.push({
          timestamp,
          filename,
          serialized
        })
        localStorage.setItem(historyKey, JSON.stringify(history))
      }
    } catch (e) {
      console.warn('Failed to save to localStorage', e)
    }
  }

  const describeExplain = (label: string, value: string) => {
    const stats = Object.fromEntries(
      value.split(',').map((s) => {
        const [desc, count] = s.trim().split(/ (?=\d+$)/)
        return [desc, parseInt(count)]
      })
    )

    const total = stats['considered'] || 0
    const ok = stats['ok'] || 0

    const explanations = Object.entries(stats)
      .filter(([key]) => key !== 'considered' && key !== 'ok')
      .map(([reason, count]) => {
        return `- ${count} ${reason.includes('fail') || reason.includes('too') ? 'failed due to' : 'with'} ${reason}`
      })

    return (
      <Box mb={1}>
        <Typography level='body-sm' fontWeight='lg' mb={0.5}>
          <strong>{label}:</strong>
        </Typography>
        <Typography fontSize='sm'>
          Out of <strong>{total}</strong> primer candidates:
          <br />
          {explanations.map((line, idx) => (
            <span key={idx}>
              {line}
              <br />
            </span>
          ))}
          ✅ <strong>{ok}</strong> primers passed all checks.
        </Typography>
      </Box>
    )
  }

  const renderInformation = (info: Record<string, any>) => {
    return Object.entries(info).map(([key, value]) => {
      if (typeof value === 'string' && key === 'warning') {
        return (
          <Typography key={key} color='warning' fontSize='sm' mb={1}>
            <strong>Warning:</strong> {value}
          </Typography>
        )
      }

      if (typeof value === 'string' && key === 'error') {
        return (
          <Typography key={key} color='danger' fontSize='sm' mb={1}>
            <strong>Error:</strong> {value}
          </Typography>
        )
      }

      if (typeof value === 'string' && key.endsWith('_EXPLAIN')) {
        const cleanLabel = key
          .replace(/_/g, ' ')
          .replace(/EXPLAIN$/, '')
          .trim()
        return describeExplain(cleanLabel, value)
      }

      //   return (
      //     <Typography key={key} fontSize='sm' mb={0.5}>
      //       <strong>{key}:</strong>{' '}
      //       {Array.isArray(value) || typeof value === 'object' ? (
      //         <pre style={{ margin: 0, whiteSpace: 'pre-wrap' }}>{JSON.stringify(value, null, 2)}</pre>
      //       ) : (
      //         String(value)
      //       )}
      //     </Typography>
      //   )
      // })
      return <></>
    })
  }

  const total = results.length
  const successCount = results.filter((r: any) => r.status === 'successful').length
  const warningCount = results.filter((r: any) => r.status === 'warning').length

  const failedCount = total - successCount - warningCount
  const errorSet = Array.from(
    new Set(
      results.filter((r: any) => r.status === 'failed' && r.information?.error).map((r: any) => r.information.error)
    )
  )

  const warningSet = Array.from(
    new Set(
      results
        .filter((r: any) => r.status === 'warning' && r.information?.warning)
        .map((r: any) => r.information.warning)
    )
  )

  const summaryText =
    `Successfully designed ${successCount} Candidate ASO sequence${successCount !== 1 ? 's' : ''}` +
    `${warningCount > 0 ? `, ${warningCount} with warning${warningCount > 1 ? 's' : ''}` : ''}` +
    `${failedCount > 0 ? `, failed ${failedCount}` : ''}.`

  const summaryDetails = `${
    [...errorSet, ...warningSet].length > 0
      ? `Reason${errorSet.length + warningSet.length > 1 ? 's' : ''}: ${[...errorSet, ...warningSet].join('; ')}`
      : ''
  }`

  return (
    <Sheet variant='outlined' sx={{ p: 2, borderRadius: 'md', mt: 3 }}>
      <Box display='flex' justifyContent='space-between' alignItems='center' mb={2}>
        <Box>
          <Typography level='h4'>Design Results</Typography>
          <Typography level='body-sm' mt={0.5} color='neutral'>
            {summaryText}
          </Typography>
          {/* <Typography level='body-sm' mt={0.5} color='neutral'>
            {summaryDetails}
          </Typography> */}
        </Box>

        <Button variant='solid' color='primary' startDecorator={<DownloadIcon />} onClick={downloadTSV}>
          Download
        </Button>
      </Box>

      <Box
        sx={{
          maxHeight: 'calc(100vh - 300px)',
          overflowY: 'auto',
          borderTop: '1px solid var(--joy-palette-neutral-outlinedBorder)',
          borderBottom: '1px solid var(--joy-palette-neutral-outlinedBorder)'
        }}>
        <Table
          aria-label='ASO Results'
          variant='soft'
          sx={{
            '& tbody tr:nth-of-type(odd)': {
              backgroundColor: 'background.surface' // 白色
            },
            '& tbody tr:nth-of-type(even)': {
              backgroundColor: 'neutral.softBg' // 浅灰
            },
            '& thead th': {
              position: 'sticky',
              top: 0,
              backgroundColor: 'background.surface',
              zIndex: 1
            }
          }}>
          <thead>
            <tr>
              <th style={{ width: 40 }} />
              <th style={{ width: 40 }}>Status</th>
              <th style={{ width: 120 }}>Name</th>
              <th style={{ width: 40 }}>ID</th>
              <th>Candidate ASO Sequence</th>
              <th style={{ width: 40 }}> </th>
            </tr>
          </thead>
          <tbody>
            {results.map((r: any, index: number) => (
              <React.Fragment key={index}>
                <tr>
                  <td>
                    <IconButton
                      variant='plain'
                      color='neutral'
                      size='sm'
                      onClick={() => setOpenIndex(openIndex === index ? null : index)}>
                      {openIndex === index ? <KeyboardArrowUpIcon /> : <KeyboardArrowDownIcon />}
                    </IconButton>
                  </td>
                  <td>
                    {r.status === 'successful' ? (
                      <Tooltip title='Successful'>
                        <CheckCircleRoundedIcon color='success' fontSize='small' />
                      </Tooltip>
                    ) : r.status === 'warning' ? (
                      <Tooltip title={r.information?.warning || 'Warning'}>
                        <ErrorOutlineRoundedIcon sx={{ color: '#FFA500' }} fontSize='small' />
                      </Tooltip>
                    ) : (
                      <Tooltip title={r.information?.error || 'Failed'}>
                        <ErrorOutlineRoundedIcon color='error' fontSize='small' />
                      </Tooltip>
                    )}
                  </td>
                  <td>
                    <Tooltip title={r.id}>
                      <Typography
                        noWrap
                        sx={{
                          maxWidth: 120, // 可根据需要调整
                          overflow: 'hidden',
                          textOverflow: 'ellipsis',
                          whiteSpace: 'nowrap',
                          display: 'inline-block',
                          verticalAlign: 'middle'
                        }}>
                        {r.id}
                      </Typography>
                    </Tooltip>
                  </td>
                  <td>
                    <Tooltip title={r.number}>
                      <Typography
                        noWrap
                        sx={{
                          maxWidth: 120, // 可根据需要调整
                          overflow: 'hidden',
                          textOverflow: 'ellipsis',
                          whiteSpace: 'nowrap',
                          display: 'inline-block',
                          verticalAlign: 'middle'
                        }}>
                        {r.number}
                      </Typography>
                    </Tooltip>
                  </td>

                  <td>
                    <Input
                      value={r.aso}
                      readOnly
                      variant='soft'
                      size='sm'
                      fullWidth
                      sx={{
                        fontFamily: 'monospace',
                        overflowX: 'auto',
                        whiteSpace: 'nowrap'
                      }}
                    />
                  </td>

                  <td>
                    <Tooltip title='Copy Candidate ASO sequence' variant='solid'>
                      <IconButton variant='outlined' color='neutral' onClick={() => copyToClipboard(r.aso)}>
                        <ContentCopyIcon fontSize='small' />
                      </IconButton>
                    </Tooltip>
                  </td>
                </tr>
                {openIndex === index && (
                  <tr>
                    <td colSpan={5} style={{ paddingLeft: 56, backgroundColor: '#f9f9f9' }}>
                      <Box sx={{ py: 1, maxHeight: 200, overflowY: 'auto' }}>{renderInformation(r.information)}</Box>
                    </td>
                  </tr>
                )}
              </React.Fragment>
            ))}
          </tbody>
        </Table>
      </Box>
    </Sheet>
  )
}

export default memo(ResultTable)
